import { Effect, Schedule } from "effect";

class HttpError {
  readonly _tag = "HttpError" as const;
  constructor(readonly status: number) {}
}

const fetchOnce = (url: string): Effect.Effect<string, HttpError> =>
  Effect.tryPromise({
    try: async () => {
      const r = await fetch(url);
      if (!r.ok) throw new HttpError(r.status);
      return r.text();
    },
    catch: (u) => (u instanceof HttpError ? u : new HttpError(0)),
  });

// exponential base + jitter, bounded by recurs(5)
const policy = Schedule.intersect(
  Schedule.jittered(Schedule.exponential("100 millis")),
  Schedule.recurs(5),
);

export const robustFetch = (url: string): Effect.Effect<string, HttpError> =>
  Effect.retry(fetchOnce(url), policy);
