import { Effect, Schedule, pipe } from "effect";

// Schedules in Effect v3 are values of type `Schedule<Out, In, R>`; they
// describe a recurrence pattern. `Schedule.intersect(a, b)` yields a
// schedule that continues only while BOTH `a` and `b` would recur — giving
// us a compound upper bound. `Schedule.upTo(d)` is a transformer applied
// via pipe to cap wall time.

class NetError { readonly _tag = "NetError" as const }

const ping: Effect.Effect<"ok", NetError> = Effect.fail(new NetError());

// exponential base + jitter + attempt cap, then bounded by wall time.
const policy = pipe(
  Schedule.intersect(
    Schedule.jittered(Schedule.exponential("100 millis")),
    Schedule.recurs(6),
  ),
  Schedule.upTo("30 seconds"),
);

export const safePing: Effect.Effect<"ok", NetError> = Effect.retry(ping, policy);
